pragma cashscript ^0.13.0;

contract BuyerSellerMultisig(pubkey buyer, pubkey seller) {
    function release(sig buyerSig, sig sellerSig) {
        require(buyer != seller);
        require(checkSig(buyerSig, buyer));
        require(checkSig(sellerSig, seller));
    }
}

pragma cashscript ^0.13.0;

contract Escrow(pubkey buyer, pubkey seller, pubkey arbiter) {
    function release(sig sig1, sig sig2) {
        require(buyer != seller);
        require(buyer != arbiter);
        require(seller != arbiter);
        require(checkMultiSig([sig1, sig2], [buyer, seller, arbiter]));
        require(tx.outputs.length == 1);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }
}

pragma cashscript ^0.13.0;

contract Escrow(
    pubkey buyer,
    pubkey seller,
    int timeoutTimestamp
) {
    function release(sig buyerSig, sig sellerSig) {
        require(buyer != seller);
        require(checkSig(buyerSig, buyer));
        require(checkSig(sellerSig, seller));
        require(tx.outputs.length == 1);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }

    function reclaim(sig buyerSig) {
        require(tx.time >= timeoutTimestamp);
        require(checkSig(buyerSig, buyer));
        require(tx.outputs.length == 1);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }
}

pragma cashscript ^0.13.0;

contract ProfessionalEscrow(
    pubkey buyer,
    pubkey seller,
    pubkey arbitrator,
    int timeoutTimestamp,
    bytes sellerLockingBytecode,
    bytes buyerLockingBytecode
) {
    function release(sig buyerSig, sig sellerSig) {
        require(buyer != seller);
        require(buyer != arbitrator);
        require(seller != arbitrator);

        require(checkSig(buyerSig, buyer));
        require(checkSig(sellerSig, seller));

        require(tx.outputs.length == 1);
        require(tx.outputs[0].lockingBytecode == sellerLockingBytecode);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }

    function disputeFavorSeller(sig buyerSig, sig arbitratorSig) {
        require(buyer != seller);
        require(buyer != arbitrator);
        require(seller != arbitrator);

        require(checkSig(buyerSig, buyer));
        require(checkSig(arbitratorSig, arbitrator));

        require(tx.outputs.length == 1);
        require(tx.outputs[0].lockingBytecode == sellerLockingBytecode);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }

    function disputeFavorBuyer(sig sellerSig, sig arbitratorSig) {
        require(buyer != seller);
        require(buyer != arbitrator);
        require(seller != arbitrator);

        require(checkSig(sellerSig, seller));
        require(checkSig(arbitratorSig, arbitrator));

        require(tx.outputs.length == 1);
        require(tx.outputs[0].lockingBytecode == buyerLockingBytecode);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }

    function refund(sig buyerSig, sig sellerSig) {
        require(buyer != seller);
        require(buyer != arbitrator);
        require(seller != arbitrator);

        require(checkSig(buyerSig, buyer));
        require(checkSig(sellerSig, seller));

        require(tx.outputs.length == 1);
        require(tx.outputs[0].lockingBytecode == buyerLockingBytecode);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }

    function timeout(sig buyerSig) {
        require(buyer != seller);
        require(buyer != arbitrator);
        require(seller != arbitrator);

        require(tx.time >= timeoutTimestamp);

        require(checkSig(buyerSig, buyer));

        require(tx.outputs.length == 1);
        require(tx.outputs[0].lockingBytecode == buyerLockingBytecode);
        require(tx.outputs[0].value == tx.inputs[this.activeInputIndex].value);
    }
}
